import {
  generateMessageId,
  createChatMessage,
  buildQuickActionPrompt,
  messagesToApiHistory,
  extractCodeBlocks,
  isApplicableContent,
  extractApplicableText,
  estimateResponseTime,
  formatEstimatedTime,
  QUICK_ACTIONS,
  type ChatMessage,
  type QuickAction,
} from '@/lib/ai/chat-service';

// ============================================================================
// generateMessageId
// ============================================================================

describe('generateMessageId', () => {
  it('returns a string starting with msg_', () => {
    const id = generateMessageId();
    expect(id).toMatch(/^msg_/);
  });

  it('generates unique IDs', () => {
    const ids = new Set(Array.from({ length: 50 }, () => generateMessageId()));
    expect(ids.size).toBe(50);
  });

  it('contains timestamp component', () => {
    const id = generateMessageId();
    const parts = id.split('_');
    expect(parts.length).toBe(3);
    const timestamp = Number(parts[1]);
    expect(timestamp).toBeGreaterThan(0);
    expect(timestamp).toBeLessThanOrEqual(Date.now());
  });

  it('contains random suffix', () => {
    const id = generateMessageId();
    const suffix = id.split('_')[2];
    expect(suffix.length).toBeGreaterThanOrEqual(5);
  });
});

// ============================================================================
// createChatMessage
// ============================================================================

describe('createChatMessage', () => {
  it('creates a user message', () => {
    const msg = createChatMessage('user', 'Hello');
    expect(msg.role).toBe('user');
    expect(msg.content).toBe('Hello');
    expect(msg.id).toMatch(/^msg_/);
    expect(msg.timestamp).toBeInstanceOf(Date);
    expect(msg.metadata).toBeUndefined();
  });

  it('creates an assistant message', () => {
    const msg = createChatMessage('assistant', 'Olá!');
    expect(msg.role).toBe('assistant');
    expect(msg.content).toBe('Olá!');
  });

  it('creates a system message', () => {
    const msg = createChatMessage('system', 'System prompt');
    expect(msg.role).toBe('system');
  });

  it('attaches metadata if provided', () => {
    const meta = { quickAction: 'rewrite', source: 'test' };
    const msg = createChatMessage('user', 'Rewrite this', meta);
    expect(msg.metadata).toEqual(meta);
  });

  it('sets timestamp close to current time', () => {
    const before = Date.now();
    const msg = createChatMessage('user', 'Test');
    const after = Date.now();
    expect(msg.timestamp.getTime()).toBeGreaterThanOrEqual(before);
    expect(msg.timestamp.getTime()).toBeLessThanOrEqual(after);
  });

  it('handles empty content', () => {
    const msg = createChatMessage('user', '');
    expect(msg.content).toBe('');
  });

  it('handles long content', () => {
    const longText = 'A'.repeat(10000);
    const msg = createChatMessage('user', longText);
    expect(msg.content.length).toBe(10000);
  });
});

// ============================================================================
// QUICK_ACTIONS
// ============================================================================

describe('QUICK_ACTIONS', () => {
  it('has at least 5 actions defined', () => {
    expect(QUICK_ACTIONS.length).toBeGreaterThanOrEqual(5);
  });

  it('each action has required fields', () => {
    for (const action of QUICK_ACTIONS) {
      expect(action.id).toBeTruthy();
      expect(action.label).toBeTruthy();
      expect(action.icon).toBeTruthy();
      expect(action.promptTemplate).toBeTruthy();
      expect(typeof action.requiresSelection).toBe('boolean');
    }
  });

  it('includes generate_script as a non-selection action', () => {
    const genScript = QUICK_ACTIONS.find((a) => a.id === 'generate_script');
    expect(genScript).toBeDefined();
    expect(genScript!.requiresSelection).toBe(false);
  });

  it('includes rewrite as a selection-required action', () => {
    const rewrite = QUICK_ACTIONS.find((a) => a.id === 'rewrite');
    expect(rewrite).toBeDefined();
    expect(rewrite!.requiresSelection).toBe(true);
  });

  it('selection-required actions contain {selection} in template', () => {
    const selectionActions = QUICK_ACTIONS.filter((a) => a.requiresSelection);
    for (const action of selectionActions) {
      expect(action.promptTemplate).toContain('{selection}');
    }
  });

  it('has unique IDs', () => {
    const ids = QUICK_ACTIONS.map((a) => a.id);
    expect(new Set(ids).size).toBe(ids.length);
  });
});

