// buildQuickActionPrompt
// ============================================================================

describe('buildQuickActionPrompt', () => {
  it('returns null for unknown action', () => {
    const result = buildQuickActionPrompt('unknown_action' as QuickAction);
    expect(result).toBeNull();
  });

  it('returns prompt for non-selection action without selection', () => {
    const result = buildQuickActionPrompt('generate_script');
    expect(result).toBeTruthy();
    expect(typeof result).toBe('string');
  });

  it('returns null for selection action without selection text', () => {
    const result = buildQuickActionPrompt('rewrite');
    expect(result).toBeNull();
  });

  it('returns null for selection action with empty selection', () => {
    const result = buildQuickActionPrompt('rewrite', '');
    expect(result).toBeNull();
  });

  it('returns null for selection action with whitespace-only selection', () => {
    const result = buildQuickActionPrompt('rewrite', '   ');
    expect(result).toBeNull();
  });

  it('replaces {selection} with provided text', () => {
    const result = buildQuickActionPrompt('rewrite', 'The quick brown fox');
    expect(result).toContain('The quick brown fox');
    expect(result).not.toContain('{selection}');
  });

  it('works with expand action', () => {
    const result = buildQuickActionPrompt('expand', 'Segurança do trabalho');
    expect(result).toContain('Segurança do trabalho');
  });

  it('works with summarize action', () => {
    const result = buildQuickActionPrompt('summarize', 'Um texto longo...');
    expect(result).toContain('Um texto longo...');
  });

  it('works with translate_en action', () => {
    const result = buildQuickActionPrompt('translate_en', 'Olá mundo');
    expect(result).toContain('Olá mundo');
  });

  it('works with translate_pt action', () => {
    const result = buildQuickActionPrompt('translate_pt', 'Hello world');
    expect(result).toContain('Hello world');
  });

  it('works with improve_tone action', () => {
    const result = buildQuickActionPrompt('improve_tone', 'Texto informal');
    expect(result).toContain('Texto informal');
  });

  it('works with add_examples action', () => {
    const result = buildQuickActionPrompt('add_examples', 'EPI são equipamentos');
    expect(result).toContain('EPI são equipamentos');
  });
});

// ============================================================================
// messagesToApiHistory
// ============================================================================

describe('messagesToApiHistory', () => {
  const makeMsg = (role: ChatMessage['role'], content: string): ChatMessage => ({
    id: `msg_${Date.now()}`,
    role,
    content,
    timestamp: new Date(),
  });

  it('returns empty array for empty messages', () => {
    expect(messagesToApiHistory([])).toEqual([]);
  });

  it('filters out system messages', () => {
    const msgs = [
      makeMsg('system', 'System prompt'),
      makeMsg('user', 'Hello'),
      makeMsg('assistant', 'Hi'),
    ];
    const result = messagesToApiHistory(msgs);
    expect(result.length).toBe(2);
    expect(result[0].role).toBe('user');
    expect(result[1].role).toBe('assistant');
  });

  it('maps to role/content format', () => {
    const msgs = [makeMsg('user', 'Hello'), makeMsg('assistant', 'Hi')];
    const result = messagesToApiHistory(msgs);
    expect(result[0]).toEqual({ role: 'user', content: 'Hello' });
    expect(result[1]).toEqual({ role: 'assistant', content: 'Hi' });
  });

  it('limits to maxMessages (default 20)', () => {
    const msgs = Array.from({ length: 30 }, (_, i) =>
      makeMsg(i % 2 === 0 ? 'user' : 'assistant', `Message ${i}`),
    );
    const result = messagesToApiHistory(msgs);
    expect(result.length).toBe(20);
  });

  it('takes the most recent messages when limited', () => {
    const msgs = Array.from({ length: 30 }, (_, i) =>
      makeMsg('user', `Message ${i}`),
    );
    const result = messagesToApiHistory(msgs, 5);
    expect(result.length).toBe(5);
    expect(result[0].content).toBe('Message 25');
    expect(result[4].content).toBe('Message 29');
  });

  it('preserves order', () => {
    const msgs = [
      makeMsg('user', 'First'),
      makeMsg('assistant', 'Second'),
      makeMsg('user', 'Third'),
    ];
    const result = messagesToApiHistory(msgs);
    expect(result.map((m) => m.content)).toEqual(['First', 'Second', 'Third']);
  });
});

// ============================================================================
// extractCodeBlocks
// ============================================================================

describe('extractCodeBlocks', () => {
  it('returns empty array for text without code blocks', () => {
    const result = extractCodeBlocks('Just regular text');
    expect(result).toEqual([]);
  });

  it('extracts single code block', () => {
    const text = 'Here is some code:\n```javascript\nconst x = 1;\n```\nDone.';
    const result = extractCodeBlocks(text);
    expect(result.length).toBe(1);
    expect(result[0].language).toBe('javascript');
    expect(result[0].code).toBe('const x = 1;');
  });

  it('extracts multiple code blocks', () => {
    const text = '```python\nprint("hi")\n```\nAnd:\n```bash\necho hello\n```';
    const result = extractCodeBlocks(text);
    expect(result.length).toBe(2);
    expect(result[0].language).toBe('python');
    expect(result[1].language).toBe('bash');
  });

  it('handles code block without language', () => {
    const text = '```\nsome code\n```';
    const result = extractCodeBlocks(text);
    expect(result.length).toBe(1);
    expect(result[0].language).toBe('text');
    expect(result[0].code).toBe('some code');
  });

  it('trims whitespace from code', () => {
    const text = '```js\n  const a = 1;  \n```';
    const result = extractCodeBlocks(text);
    expect(result[0].code).toBe('const a = 1;');
  });

  it('handles multi-line code blocks', () => {
    const text = '```typescript\nconst a = 1;\nconst b = 2;\nconst c = a + b;\n```';
    const result = extractCodeBlocks(text);
    expect(result[0].code).toContain('const a = 1;');
    expect(result[0].code).toContain('const c = a + b;');
  });
});

// ============================================================================
// isApplicableContent
// ============================================================================

describe('isApplicableContent', () => {
  it('returns false for empty string', () => {
    expect(isApplicableContent('')).toBe(false);
  });

  it('returns false for whitespace-only', () => {
    expect(isApplicableContent('   ')).toBe(false);
  });

  it('returns true for content with code blocks', () => {
    expect(isApplicableContent('```js\ncode\n```')).toBe(true);
  });

  it('returns true for quoted text', () => {
    expect(isApplicableContent('"Quoted text"')).toBe(true);
  });

  it('returns true for content starting with >', () => {
    expect(isApplicableContent('> Blockquote content')).toBe(true);
  });

  it('returns true for bullet point lists', () => {
    expect(isApplicableContent('- Item 1\n- Item 2')).toBe(true);
  });

  it('returns true for numbered lists', () => {
    expect(isApplicableContent('1. First item\n2. Second item')).toBe(true);
  });

  it('returns true for long content (>100 chars)', () => {
    const longText = 'A'.repeat(101);
    expect(isApplicableContent(longText)).toBe(true);
  });

  it('returns false for short plain text', () => {
    expect(isApplicableContent('Ok')).toBe(false);
  });

  it('returns true for content with asterisk bullets', () => {
    expect(isApplicableContent('* Item A\n* Item B')).toBe(true);
  });

  it('returns true for content with bullet char (•)', () => {
    expect(isApplicableContent('• Ponto 1')).toBe(true);
  });
});

// ============================================================================
// extractApplicableText
// ============================================================================

describe('extractApplicableText', () => {
  it('removes "Aqui está:" prefix', () => {
    const result = extractApplicableText('Aqui está: O texto reescrito.');
    expect(result).toBe('O texto reescrito.');
  });

  it('removes "Segue:" prefix', () => {
    const result = extractApplicableText('Segue: Conteúdo importante');
    expect(result).toBe('Conteúdo importante');
  });

  it('removes "Here\'s:" prefix', () => {
    const result = extractApplicableText("Here's: The rewritten text");
    expect(result).toBe('The rewritten text');
  });

  it('extracts code from code blocks', () => {
    const result = extractApplicableText('Sugiro:\n```text\nLinha 1\nLinha 2\n```');
    expect(result).toContain('Linha 1');
    expect(result).toContain('Linha 2');
  });

  it('removes markdown bold markers', () => {
    const result = extractApplicableText('**Texto em negrito** e *itálico*');
    expect(result).toBe('Texto em negrito e itálico');
  });

  it('handles plain text without prefixes', () => {
    const result = extractApplicableText('Just plain text');
    expect(result).toBe('Just plain text');
  });

  it('trims whitespace', () => {
    const result = extractApplicableText('  Spaced out  ');
    expect(result).toBe('Spaced out');
  });
});

// ============================================================================
// estimateResponseTime
// ============================================================================

describe('estimateResponseTime', () => {
  it('returns base time for 0 message length and 0 history', () => {
    const result = estimateResponseTime(0, 0);
    expect(result).toBe(2000);
  });

  it('increases with message length', () => {
    const short = estimateResponseTime(10, 0);
    const long = estimateResponseTime(1000, 0);
    expect(long).toBeGreaterThan(short);
  });

  it('increases with history length', () => {
    const noHistory = estimateResponseTime(100, 0);
    const withHistory = estimateResponseTime(100, 10);
    expect(withHistory).toBeGreaterThan(noHistory);
  });

  it('returns positive number for all inputs', () => {
    expect(estimateResponseTime(0, 0)).toBeGreaterThan(0);
    expect(estimateResponseTime(100, 5)).toBeGreaterThan(0);
    expect(estimateResponseTime(5000, 20)).toBeGreaterThan(0);
  });

  it('calculates correctly with known values', () => {
    // base(2000) + 100*2 + 5*200 = 2000 + 200 + 1000 = 3200
    expect(estimateResponseTime(100, 5)).toBe(3200);
  });
});

// ============================================================================
// formatEstimatedTime
// ============================================================================

describe('formatEstimatedTime', () => {
  it('formats sub-second as "menos de 1s"', () => {
    expect(formatEstimatedTime(500)).toBe('menos de 1s');
  });

  it('formats seconds', () => {
    expect(formatEstimatedTime(5000)).toBe('~5s');
  });

  it('formats exact minutes', () => {
    expect(formatEstimatedTime(60000)).toBe('~1min');
  });

  it('formats minutes and seconds', () => {
    expect(formatEstimatedTime(90000)).toBe('~1min 30s');
  });

  it('formats 2 minutes', () => {
    expect(formatEstimatedTime(120000)).toBe('~2min');
  });

  it('formats edge case of 999ms', () => {
    expect(formatEstimatedTime(999)).toBe('menos de 1s');
  });

  it('formats 1 second', () => {
    expect(formatEstimatedTime(1000)).toBe('~1s');
  });

  it('handles 0ms', () => {
    expect(formatEstimatedTime(0)).toBe('menos de 1s');
  });
});

// ============================================================================
// sendChatMessage (integration - mocked fetch)
// ============================================================================

describe('sendChatMessage', () => {
  const originalFetch = global.fetch;

  afterEach(() => {
    global.fetch = originalFetch;
  });

  it('sends request to /api/ai/chat', async () => {
    const { sendChatMessage } = await import('@/lib/ai/chat-service');

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      json: () =>
        Promise.resolve({
          success: true,
          message: 'Resposta da IA',
          suggestions: [],
        }),
    });

    const result = await sendChatMessage('Hello', []);
    expect(result.success).toBe(true);
    expect(result.message).toBe('Resposta da IA');
    expect(global.fetch).toHaveBeenCalledWith('/api/ai/chat', expect.objectContaining({
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
    }));
  });

  it('handles HTTP error response', async () => {
    const { sendChatMessage } = await import('@/lib/ai/chat-service');

    global.fetch = jest.fn().mockResolvedValue({
      ok: false,
      status: 500,
      json: () => Promise.resolve({ error: 'Internal Server Error' }),
    });

    const result = await sendChatMessage('Hello', []);
    expect(result.success).toBe(false);
    expect(result.error).toBeTruthy();
  });

  it('handles network error', async () => {
    const { sendChatMessage } = await import('@/lib/ai/chat-service');

    global.fetch = jest.fn().mockRejectedValue(new Error('Network error'));

    const result = await sendChatMessage('Hello', []);
    expect(result.success).toBe(false);
    expect(result.error).toBe('Network error');
  });

  it('sends project context when provided', async () => {
    const { sendChatMessage } = await import('@/lib/ai/chat-service');

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      json: () =>
        Promise.resolve({ success: true, message: 'ok', suggestions: [] }),
    });

    await sendChatMessage('Hello', [], { tracks: 5, clips: 10, duration: 300 });

    const callBody = JSON.parse((global.fetch as jest.Mock).mock.calls[0][1].body);
    expect(callBody.context.tracks).toBe(5);
    expect(callBody.context.clips).toBe(10);
    expect(callBody.context.duration).toBe(300);
  });

  it('sends message history', async () => {
    const { sendChatMessage } = await import('@/lib/ai/chat-service');

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      json: () =>
        Promise.resolve({ success: true, message: 'ok', suggestions: [] }),
    });

    const history: ChatMessage[] = [
      { id: '1', role: 'user', content: 'First', timestamp: new Date() },
      { id: '2', role: 'assistant', content: 'Reply', timestamp: new Date() },
    ];

    await sendChatMessage('New message', history);

    const callBody = JSON.parse((global.fetch as jest.Mock).mock.calls[0][1].body);
    expect(callBody.history.length).toBe(2);
  });

  it('returns suggestions from API', async () => {
    const { sendChatMessage } = await import('@/lib/ai/chat-service');

    const suggestions = [
      { type: 'script', title: 'Improve', description: 'Test', confidence: 0.8 },
    ];

    global.fetch = jest.fn().mockResolvedValue({
      ok: true,
      json: () =>
        Promise.resolve({ success: true, message: 'ok', suggestions }),
    });

    const result = await sendChatMessage('Hello', []);
    expect(result.suggestions.length).toBe(1);
    expect(result.suggestions[0].type).toBe('script');
  });

  it('handles non-JSON error response', async () => {
    const { sendChatMessage } = await import('@/lib/ai/chat-service');

    global.fetch = jest.fn().mockResolvedValue({
      ok: false,
      status: 502,
      json: () => Promise.reject(new Error('Not JSON')),
    });

    const result = await sendChatMessage('Hello', []);
    expect(result.success).toBe(false);
    expect(result.error).toContain('502');
  });
});
